    73→
    74→  // Account linking: if the provider uses a prefix (e.g. Google "google_"),
    75→  // check if a user with the same email already exists from another provider.
    76→  // If yes, update their profile and return them (no duplicate account created).
    77→  if (email && idPrefix) {
    78→    const [existingByEmail] = await db
    79→      .select()
    80→      .from(usersTable)
    81→      .where(eq(usersTable.email, email))
    82→      .limit(1);
    83→
    84→    if (existingByEmail) {
    85→      const [linked] = await db
    86→        .update(usersTable)
    87→        .set({
    88→          firstName: firstName || existingByEmail.firstName,
    89→          lastName: lastName || existingByEmail.lastName,
    90→          profileImageUrl: profileImageUrl ?? existingByEmail.profileImageUrl,
    91→          updatedAt: new Date(),
    92→        })
    93→        .where(eq(usersTable.id, existingByEmail.id))
    94→        .returning();
    95→      return linked;
    96→    }
    97→  }
