   442→function hashPassword(password: string): Promise<string> {
   443→  return new Promise((resolve, reject) => {
   444→    const salt = crypto.randomBytes(16).toString("hex");
   445→    crypto.scrypt(password, salt, 64, (err, derived) => {
   446→      if (err) reject(err);
   447→      else resolve(`${salt}:${derived.toString("hex")}`);
   448→    });
   449→  });
   450→}
   451→
   452→function verifyPassword(password: string, stored: string): Promise<boolean> {
   453→  return new Promise((resolve, reject) => {
   454→    const [salt, hash] = stored.split(":");
   455→    if (!salt || !hash) { resolve(false); return; }
   456→    crypto.scrypt(password, salt, 64, (err, derived) => {
   457→      if (err) reject(err);
   458→      else resolve(crypto.timingSafeEqual(Buffer.from(hash, "hex"), derived));
   459→    });
   460→  });
   461→}
