    96→/* ─────────────────────────────────────────────────────────────────────────────
    97→   BRAND PALETTE (5 colores)
    98→   #213756  Deep Space Blue  → primary surface / foreground text
    99→   #A3A7AD  Cool Steel       → texto muted (ambos modos)
   100→   #C5C6C8  Silver           → bordes y divisores
   101→   #EEEEEE  Platinum         → fondo light / texto claro dark
   102→   #E7E7E7  Alabaster Grey   → fondo de cards light / muted bg
   103→
   104→   HSL conversiones:
   105→   #213756 → hsl(215 44% 23%)
   106→   #A3A7AD → hsl(216 5% 66%)
   107→   #C5C6C8 → hsl(210 2% 78%)
   108→   #EEEEEE → hsl(0 0% 93%)
   109→   #E7E7E7 → hsl(0 0% 90%)
   110→   ───────────────────────────────────────────────────────────────────────────── */
   111→
   112→/* LIGHT MODE */
   113→:root {
   114→  /* Navy → paleta brand light */
   115→  --theme-white:      #213756;   /* text-white = Deep Space Blue en light */
   116→  --theme-navy:       #EEEEEE;   /* Platinum */
   117→  --theme-navy-2:     #E7E7E7;   /* Alabaster */
   118→  --theme-navy-3:     #F3F4F5;   /* Entre Platinum y blanco */
