   126→
   127→  --elevate-1: rgba(33,55,86, .03);
   128→  --elevate-2: rgba(33,55,86, .07);
   129→
   130→  /* surfaces */
   131→  --background: 0 0% 93%;          /* Platinum #EEEEEE */
   132→  --foreground: 215 44% 23%;       /* Deep Space Blue #213756 */
   133→  --border: 210 2% 78%;            /* Silver #C5C6C8 */
   134→  --input: 210 2% 78%;             /* Silver */
   135→  --ring: 215 44% 23%;             /* Deep Space Blue */
   136→
   137→  /* cards */
   138→  --card: 0 0% 100%;               /* blanco puro — máximo contraste sobre Platinum */
   139→  --card-foreground: 215 44% 23%;
   140→  --card-border: 210 2% 78%;       /* Silver */
   141→
   142→  /* popovers */
   143→  --popover: 0 0% 100%;
   144→  --popover-foreground: 215 44% 23%;
   145→  --popover-border: 210 2% 78%;
   146→
   147→  /* primary = Deep Space Blue */
   148→  --primary: 215 44% 23%;
   149→  --primary-foreground: 0 0% 93%;  /* Platinum */
   150→
   151→  /* secondary = Alabaster */
   152→  --secondary: 0 0% 90%;           /* Alabaster #E7E7E7 */
   153→  --secondary-foreground: 215 44% 23%;
   154→
   155→  /* muted */
   156→  --muted: 0 0% 90%;               /* Alabaster */
   157→  --muted-foreground: 216 5% 66%; /* Cool Steel #A3A7AD */
   158→
   159→  /* accent = Gold (brand accent, se mantiene) */
   160→  --accent: 43 63% 47%;
