   170→  --sidebar-foreground: 215 44% 23%;
   171→  --sidebar-border: 210 2% 78%;
   172→  --sidebar-primary: 215 44% 23%;
   173→  --sidebar-primary-foreground: 0 0% 100%;
   174→  --sidebar-accent: 0 0% 90%;
   175→  --sidebar-accent-foreground: 215 44% 23%;
   176→  --sidebar-ring: 215 44% 23%;
   177→
   178→  /* charts — derivados del brand */
   179→  --chart-1: 43 63% 47%;           /* Gold */
   180→  --chart-2: 215 44% 23%;          /* Deep Space Blue */
   181→  --chart-3: 216 5% 66%;           /* Cool Steel */
   182→  --chart-4: 210 2% 78%;           /* Silver */
   183→  --chart-5: 215 44% 35%;          /* Deep Space Blue claro */
   184→}
