    29→function useCountUp(end: number, duration: number = 2000) {
    30→  const [count, setCount] = useState(0);
    31→  const [hasAnimated, setHasAnimated] = useState(false);
    32→  const ref = useRef<HTMLSpanElement>(null);
    33→
    34→  useEffect(() => {
    35→    const observer = new IntersectionObserver((entries) => {
    36→      if (entries[0].isIntersecting && !hasAnimated) {
    37→        setHasAnimated(true);
    38→        let startTimestamp: number | null = null;
    39→        const step = (timestamp: number) => {
    40→          if (!startTimestamp) startTimestamp = timestamp;
    41→          const progress = Math.min((timestamp - startTimestamp) / duration, 1);
    42→          setCount(Math.floor(progress * end));
    43→          if (progress < 1) {
    44→            window.requestAnimationFrame(step);
    45→          }
    46→        };
    47→        window.requestAnimationFrame(step);
    48→      }
    49→    }, { threshold: 0.1 });
    50→
    51→    if (ref.current) observer.observe(ref.current);
    52→    return () => observer.disconnect();
    53→  }, [end, duration, hasAnimated]);
    54→
    55→  return { count, ref };
    56→}
